#include <iostream>
using namespace std;

int main() {
  int myInt = 9;
  double myDouble = myInt;  // Implicit int to double

  double pi = 3.14159;
  int truncated = pi;       // Implicit double to int (warning)

  cout << "Int to double: " << myDouble << endl;
  cout << "Double to int (truncated): " << truncated << endl;
  return 0;
}
